    (limit == ZOPFLI_MAX_MATCH &&
     __CPROVER_old(s->lmc->dist[pos - s->blockstart]) == 0)
    ==> (s->lmc->length[pos - s->blockstart] ==
         (length < ZOPFLI_MIN_MATCH ? 0 : length)))
__CPROVER_ensures(
    (limit == ZOPFLI_MAX_MATCH &&
     __CPROVER_old(s->lmc->dist[pos - s->blockstart]) == 0)
    ==> (s->lmc->dist[pos - s->blockstart] ==
